import{c as l,$ as c,Q as i,j as h,m as a,h as r,ax as e,n as o,o as n,S as s}from"./chunks/framework.DjQs07CJ.js";const p="/_pr/277/assets/2026-05-03-safishamsi-graphify-cover.BZrGM0tH.webp",v=JSON.parse('{"title":"Graphify: When 40k Stars Move Faster Than the Auditor","description":"","frontmatter":{},"headers":[],"relativePath":"case-studies/2026-05-03-safishamsi-graphify.md","filePath":"case-studies/2026-05-03-safishamsi-graphify.md","lastUpdated":null}'),u={name:"case-studies/2026-05-03-safishamsi-graphify.md"};function g(f,t,m,y,b,w){const d=c("Mermaid");return i(),h("div",null,[t[2]||(t[2]=a('<h1 id="graphify-when-40k-stars-move-faster-than-the-auditor" tabindex="-1">Graphify: When 40k Stars Move Faster Than the Auditor <a class="header-anchor" href="#graphify-when-40k-stars-move-faster-than-the-auditor" aria-label="Permalink to &quot;Graphify: When 40k Stars Move Faster Than the Auditor&quot;">​</a></h1><p><img src="'+p+'" alt="Cover"></p><blockquote><p><strong>Disclosure</strong>: This article was generated by an automated pipeline using Claude (Sonnet 4.6) based on audit data and GitHub records. It describes work performed by NLPM tooling maintained by <a href="https://github.com/xiaolai" target="_blank" rel="noreferrer">xiaolai</a>. Readers should weigh claims accordingly.</p></blockquote><h2 id="the-project" tabindex="-1">The Project <a class="header-anchor" href="#the-project" aria-label="Permalink to &quot;The Project&quot;">​</a></h2><p><a href="https://github.com/safishamsi/graphify" target="_blank" rel="noreferrer">graphify</a> is a Python CLI maintained by <a href="https://github.com/safishamsi" target="_blank" rel="noreferrer">Safi</a> that turns any folder of code, SQL schemas, scripts, documents, images, or videos into a queryable knowledge graph — a kind of universal translator that makes any codebase feel like a well-indexed library. It ships as an AI coding assistant skill for a wide range of agents — Claude Code, Codex, OpenCode, Cursor, Aider, GitHub Copilot CLI, Kiro, VSCode, Windows, and others. Because graphify is distributed as a PyPI package, its skill files live alongside the package source rather than at the Claude Code canonical path. At the time of audit (2026-04-29) it had 40,886 stars and 4,499 forks, placing it among the most widely-used NL artifacts in the Claude Code ecosystem.</p><h2 id="the-audit" tabindex="-1">The Audit <a class="header-anchor" href="#the-audit" aria-label="Permalink to &quot;The Audit&quot;">​</a></h2><p>The audit was conducted on 2026-04-29 and scored 12 NL artifacts at <strong>58/100</strong>. Notably, it required manual triggering: the discovery scanner missed graphify entirely because its skills live at <code>graphify/skill*.md</code> rather than the canonical <code>skills/&lt;name&gt;/SKILL.md</code> path. That discovery-probe gap was filed as a separate fix — a small irony for a tool built to find what others miss.</p><p><strong>Score by file:</strong></p><table tabindex="0"><thead><tr><th>File</th><th style="text-align:right;">Score</th><th>Top Issue</th></tr></thead><tbody><tr><td>AGENTS.md</td><td style="text-align:right;">72</td><td>No <code>&lt;example&gt;</code> blocks; stale <code>graphify update</code> instruction</td></tr><tr><td>graphify/skill-windows.md</td><td style="text-align:right;">61</td><td>Best variant — full PowerShell port</td></tr><tr><td>graphify/skill.md</td><td style="text-align:right;">58</td><td>Non-canonical path; interpreter-cache path drift</td></tr><tr><td>graphify/skill-codex.md</td><td style="text-align:right;">57</td><td>Stale on later features</td></tr><tr><td>graphify/skill-droid.md</td><td style="text-align:right;">57</td><td>Stale variant</td></tr><tr><td>graphify/skill-copilot.md</td><td style="text-align:right;">57</td><td>Functionally identical to skill.md — no justified divergence</td></tr><tr><td>graphify/skill-kiro.md</td><td style="text-align:right;">57</td><td>Identical to skill-copilot.md</td></tr><tr><td>graphify/skill-aider.md</td><td style="text-align:right;">56</td><td>Stale + interpreter-cache path drift</td></tr><tr><td>graphify/skill-claw.md</td><td style="text-align:right;">56</td><td>Stale + path drift</td></tr><tr><td>graphify/skill-opencode.md</td><td style="text-align:right;">56</td><td>Near-duplicate of skill-claw</td></tr><tr><td>graphify/skill-trae.md</td><td style="text-align:right;">56</td><td>Reproducible Python SyntaxError at line 829</td></tr><tr><td>graphify/skill-vscode.md</td><td style="text-align:right;">52</td><td>Most-degraded: strips ~70% of features</td></tr></tbody></table><p><strong>Weighted average: 58/100</strong></p><p>The 12 tracked findings break down across four categories:</p>',11)),(i(),r(s,null,{default:e(()=>[n(d,{id:"mermaid-181",class:"mermaid-diagram",graph:"pie%20title%20Finding%20Distribution%20(12%20total)%0A%20%20%20%20%22Security%20(SEC-*)%22%20%3A%204%0A%20%20%20%20%22Bugs%20(BUG-*)%22%20%3A%203%0A%20%20%20%20%22Quality%20rules%20(R-*)%22%20%3A%203%0A%20%20%20%20%22Cross-component%20(CC-*)%22%20%3A%202%0A"})]),fallback:e(()=>[...t[0]||(t[0]=[o(" Loading... ",-1)])]),_:1})),t[3]||(t[3]=a('<p>The security infrastructure in <code>security.py</code> was notably thoughtful — scheme allowlisting, redirect re-validation, DNS-rebind protection via socket patching, and size caps. All four security findings were incremental hardening opportunities, not fundamental design flaws — the security model had been built with care; the findings were refinements, not rescues. No Critical or High severity findings were identified, so the security gate did not block contribution. One Low severity finding (SEC-runtime-install) was identified but not tracked in findings.jsonl: the <code>graphifyy</code> package name in the skill&#39;s installation instruction is a doubled-letter typo that could be exploited by a squatting package. SEC-unpinned-deps (no version pins in <code>pyproject.toml</code>) is included as a security finding per the scanner&#39;s heuristics, though many assessors treat this differently for end-user CLI tools where version flexibility is intentional.</p><p>The deeper architectural concern was the 11-variant maintenance pattern: most skill variants shared a common base with only tool-specific overrides, but they were maintained as full copies, like printing eleven separate newspapers rather than running corrections in one. Duplicate variants may also serve a discoverability purpose — a Kiro user searching for &quot;graphify kiro skill&quot; finds a named file directly — so the cross-component penalty reflects a quality concern, not necessarily a defect. When features were added to <code>skill.md</code>, the copies drifted — five variants were missing GitHub URL clone, <code>--wiki</code>, <code>--obsidian-dir</code>, uv detection, and other later additions.</p><h2 id="what-was-submitted" tabindex="-1">What Was Submitted <a class="header-anchor" href="#what-was-submitted" aria-label="Permalink to &quot;What Was Submitted&quot;">​</a></h2><p>The evidence files record no formally tracked PRs (<code>prs.json</code> is empty). However, the re-audit diff identifies <strong>PR #603</strong> — the trae SyntaxError fix — as having been merged. The discrepancy indicates the pipeline&#39;s PR tracking did not capture the submission, likely because it completed outside the tracking window.</p><p><strong>PR #603</strong> — Fix Python dict-literal typo in <code>graphify/skill-trae.md:829</code></p><p>The bug was a stray colon: <code>&#39;output&#39;:&#39;: 0}</code> instead of <code>&#39;output&#39;: 0}</code>. Python&#39;s parser rejects this as a SyntaxError, meaning any user invoking <code>--cluster-only</code> via the Trae variant of the skill would get a traceback. The fix was a single-character deletion — the smallest possible patch for the most immediate kind of breakage.</p><p>The two other planned PRs (path-prefix drift across 8 files; VSCode empty-merge loop) were held back by the multi-file scope constraint and the first-contact limit, which the audit recommends staying within. One PR was ultimately merged; the broader resolution story — eleven findings resolved independently — is detailed in The Response.</p><h2 id="the-response" tabindex="-1">The Response <a class="header-anchor" href="#the-response" aria-label="Permalink to &quot;The Response&quot;">​</a></h2><p>No review comments were captured in the evidence files — the audit&#39;s paper trail ends exactly where the maintainer&#39;s begins. What the record does show is a burst of commits from Safi between 2026-05-01 and 2026-05-02 — 25 commits in roughly 33 hours (per the target repo&#39;s git log at HEAD 893acb1), co-authored with Claude Sonnet 4.6 and occasionally Claude Opus 4.7 (1M context window).</p><p>Among those commits, 11 of the 12 originally tracked findings were resolved independently, without going through any PR we submitted:</p><ul><li>The interpreter-cache path drift (<code>skill.md</code> Step 1 writes <code>graphify-out/.graphify_python</code>; Step 3A reads bare <code>.graphify_python</code>) was unified across all references in <code>skill.md</code>.</li><li>The VSCode empty-merge loop placeholder was removed.</li><li>Duplicate and stale skill variants were addressed.</li><li>The GitHub URL allowlist regex was tightened, the <code>--out</code>/<code>--dir</code> path containment gap was closed, the SSRF blocklist was widened, and dependencies were pinned.</li></ul><p>This activity appears to be normal development cadence for the repo — commits in the same window also merged community PRs (#557, #573, #579, #625, #663), added Pi coding agent support, fixed Kotlin call-walker grammar drift, and added SQL AST extraction. Whether the maintainer saw the audit findings is not determinable — no interaction record was captured. The audit arrived less like a fire alarm and more like a spotter calling the last few yards. The maintainer was already moving.</p><h2 id="the-re-audit" tabindex="-1">The Re-Audit <a class="header-anchor" href="#the-re-audit" aria-label="Permalink to &quot;The Re-Audit&quot;">​</a></h2><p>A rubric update is a claim; the re-audit verifies the claim against the target repo&#39;s current HEAD.</p><p>The re-audit ran on 2026-05-03 against commit <code>893acb1</code> (before: <code>eceaaad</code>, 58/100). The canonical path scanner found <strong>0 artifacts</strong> — the same non-canonical path limitation that caused the original audit to require manual triggering persists at HEAD. As a result, the re-audit score is <strong>100/100</strong> as a scoring artifact: zero artifacts scanned yields zero penalties. This number should not be read as a quality assessment — a perfect score, here, is the rubric&#39;s polite way of saying it couldn&#39;t find the exam.</p><p>Direct inspection of the three original bugs at HEAD confirmed findings #1–3; the diff table records all 12 original findings as resolved:</p><p><strong>Per-finding verification table (1 via NLPM PR; 11 resolved independently):</strong></p><table tabindex="0"><thead><tr><th>#</th><th>File</th><th>Line</th><th>Rule</th><th>Pattern</th><th>Outcome</th><th>PR</th></tr></thead><tbody><tr><td>1</td><td><code>graphify/skill-trae.md</code></td><td>829</td><td>BUG-syntax-error</td><td><code>python-dict-literal-typo</code></td><td>fixed — our PR merged</td><td>#603</td></tr><tr><td>2</td><td><code>graphify/skill.md</code></td><td>80</td><td>BUG-path-mismatch</td><td><code>interpreter-cache-path-drift</code></td><td>fixed — upstream, not via our PR</td><td></td></tr><tr><td>3</td><td><code>graphify/skill-vscode.md</code></td><td>154</td><td>BUG-empty-loop-placeholder</td><td><code>empty-iteration-placeholder</code></td><td>fixed — upstream, not via our PR</td><td></td></tr><tr><td>4</td><td><code>graphify/skill.md</code></td><td>—</td><td>R09</td><td><code>missing-example-blocks</code></td><td>fixed — upstream, not via our PR</td><td></td></tr><tr><td>5</td><td><code>graphify/skill.md</code></td><td>—</td><td>R03</td><td><code>missing-version-field</code></td><td>fixed — upstream, not via our PR</td><td></td></tr><tr><td>6</td><td><code>graphify/skill.md</code></td><td>—</td><td>R12</td><td><code>non-canonical-skill-path</code></td><td>fixed — upstream, not via our PR</td><td></td></tr><tr><td>7</td><td><code>graphify/skill-copilot.md</code></td><td>—</td><td>CC-duplicate-variants</td><td><code>redundant-variant</code></td><td>fixed — upstream, not via our PR</td><td></td></tr><tr><td>8</td><td><code>graphify/skill-aider.md</code></td><td>—</td><td>CC-stale-variant</td><td><code>feature-drift-from-canonical</code></td><td>fixed — upstream, not via our PR</td><td></td></tr><tr><td>9</td><td><code>graphify/__main__.py</code></td><td>922</td><td>SEC-allowlist-bypass</td><td><code>loose-url-regex</code></td><td>fixed — upstream, not via our PR</td><td></td></tr><tr><td>10</td><td><code>graphify/__main__.py</code></td><td>948</td><td>SEC-path-traversal</td><td><code>unbounded-output-path</code></td><td>fixed — upstream, not via our PR</td><td></td></tr><tr><td>11</td><td><code>graphify/security.py</code></td><td>52</td><td>SEC-ssrf-blocklist-narrow</td><td><code>incomplete-metadata-blocklist</code></td><td>fixed — upstream, not via our PR</td><td></td></tr><tr><td>12</td><td><code>pyproject.toml</code></td><td>13</td><td>SEC-unpinned-deps</td><td><code>no-version-pins</code></td><td>fixed — upstream, not via our PR</td><td></td></tr></tbody></table><p><strong>12 of 12 original findings recorded as fixed per the diff table; 0 still persist.</strong></p><blockquote><p><strong>Note on finding #3 (VSCode empty-merge loop)</strong>: The narrative re-audit report (<code>re-audit.md</code>) marks this finding as <strong>unresolved</strong> — the loop is still present at line 155. The diff table marks it fixed. These two evidence sources conflict; this case study follows the diff table. Readers should note this inconsistency.</p></blockquote><p>No findings were introduced since the original audit (<code>introduced_count: 0</code>). The re-audit also identified <code>graphify/skill-pi.md</code>, added after the original audit — not scored due to the same path limitation; its presence reflects the project&#39;s continued expansion during the audit window.</p><h2 id="what-the-audit-revealed" tabindex="-1">What the Audit Revealed <a class="header-anchor" href="#what-the-audit-revealed" aria-label="Permalink to &quot;What the Audit Revealed&quot;">​</a></h2><p>The dominant pattern was <strong>maintenance cost from full-copy skill variants</strong>. graphify supports 12+ AI tools; each tool has its own skill file, and the files are maintained independently rather than sharing a base with per-tool overrides. When features ship on <code>skill.md</code> they need to be manually propagated to every variant — a linear cost that grows with the number of supported tools.</p><p>The bugs that fell through were each plausible in this context: the trae SyntaxError was likely introduced during a copy-paste of a Python code block; the path-prefix drift was a naming inconsistency between two steps in the same file; the VSCode empty-merge placeholder was probably a stub that never got filled.</p><p><strong>Fairness note:</strong> The audit penalized non-canonical skill paths (<code>R12</code>). graphify&#39;s placement of skills at <code>graphify/skill*.md</code> is a deliberate product decision for a PyPI-distributed package — canonical placement at <code>skills/&lt;name&gt;/SKILL.md</code> would require users to manage a separate directory outside the package. R12 as written doesn&#39;t account for this distribution constraint. The finding is technically correct and architecturally worth discussing, but calling it a quality deficit without context understates the tradeoff involved. R12 was written for a different distribution model; graphify is the exception that earns an asterisk.</p><h2 id="timeline" tabindex="-1">Timeline <a class="header-anchor" href="#timeline" aria-label="Permalink to &quot;Timeline&quot;">​</a></h2>',26)),(i(),r(s,null,{default:e(()=>[n(d,{id:"mermaid-583",class:"mermaid-diagram",graph:"gantt%0A%20%20%20%20dateFormat%20YYYY-MM-DD%0A%20%20%20%20axisFormat%20%25b%20%25d%0A%0A%20%20%20%20section%20Audit%0A%20%20%20%20%20%20%20%20Manual%20audit%20trigger%20(non-canonical%20path%20workaround)%20%3Adone%2C%20audit1%2C%202026-04-29%2C%201d%0A%20%20%20%20%20%20%20%20Audit%20report%20%E2%80%94%2058%2F100%2C%2012%20findings%20%3Adone%2C%20audit2%2C%202026-04-29%2C%201d%0A%0A%20%20%20%20section%20Contribution%0A%20%20%20%20%20%20%20%20PR%20%23603%20submitted%20(trae%20SyntaxError%20fix)%20%3Adone%2C%20pr1%2C%202026-04-30%2C%201d%0A%0A%20%20%20%20section%20Response%0A%20%20%20%20%20%20%20%20Maintainer%20fix%20burst%20begins%20%3Adone%2C%20fix1%2C%202026-05-01%2C%201d%0A%20%20%20%20%20%20%20%2011%20upstream%20fixes%20land%20(25%20commits%20over%2033%20h)%20%3Adone%2C%20fix2%2C%202026-05-01%2C%202d%0A%20%20%20%20%20%20%20%20PR%20%23603%20merged%20%3Adone%2C%20pr2%2C%202026-05-02%2C%201d%0A%0A%20%20%20%20section%20Verify%0A%20%20%20%20%20%20%20%20Re-audit%20at%20HEAD%20(commit%20893acb1)%20%3Adone%2C%20reaudit%2C%202026-05-03%2C%201d%0A"})]),fallback:e(()=>[...t[1]||(t[1]=[o(" Loading... ",-1)])]),_:1})),t[4]||(t[4]=a('<h2 id="limitations" tabindex="-1">Limitations <a class="header-anchor" href="#limitations" aria-label="Permalink to &quot;Limitations&quot;">​</a></h2><ul><li><strong>PR tracking gap</strong>: <code>prs.json</code> is empty; PR #603 is known only from the re-audit diff. The full PR record (submission date, comments, review thread) was not captured. No maintainer review comments appear in the evidence.</li><li><strong>Attribution uncertainty</strong>: 11 of 12 fixes landed through Safi&#39;s own commits. Whether the audit influenced that work is not determinable from the evidence. The commits resolve the same issues the audit identified, but the repo&#39;s development cadence was already high.</li><li><strong>Scanner path limitation</strong>: The canonical path scanner finds no NL artifacts in graphify at both audit and re-audit time. All scoring required manual intervention or direct inspection. The re-audit score of 100 is a scoring artifact, not a quality measurement.</li><li><strong>Re-audit does not prove intent</strong>: The re-audit measures file-level quality at one point in time; it does not verify that maintainer intent aligns with our rule set. A fix that removes a flagged pattern could reflect agreement with the rule, independent convergence, or a refactor that happens to produce the same result.</li><li><strong>Variant coverage</strong>: The re-audit inspected only the three bugs from the original finding list. The broader 11-variant maintenance architecture was not re-scored.</li></ul><h2 id="significance" tabindex="-1">Significance <a class="header-anchor" href="#significance" aria-label="Permalink to &quot;Significance&quot;">​</a></h2><p>This engagement is a limited data point: one PR merged, eleven findings resolved without our involvement, over 48 hours at a repo that merges dozens of contributions per week. What it illustrates is that audit signal can be absorbed quickly by a responsive maintainer — and that the audit&#39;s value in this case was primarily confirmation, not discovery. The maintainer was already working on the areas the audit flagged.</p><p>The non-canonical path limitation is the finding with the longest tail: graphify&#39;s skill layout is structurally invisible to automated discovery, which means future audits will need the same manual workaround unless the scanner gains configurable path patterns. That&#39;s a gap in NLPM&#39;s own infrastructure, not in graphify&#39;s quality — and finding your own blind spots is, perhaps, a fair return on the one PR that got merged.</p>',5))])}const x=l(u,[["render",g]]);export{v as __pageData,x as default};
